import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import './ProductDetail.css';
import axios from 'axios';
import Footer from './Footer';

function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [product, setProduct] = useState(null);
  const [selectedImg, setSelectedImg] = useState(0);
  const [selectedSize, setSelectedSize] = useState(null);

  // pincode
  const [pincode, setPincode] = useState('');
  const [pinMsg, setPinMsg] = useState('');

  // related
  const [related, setRelated] = useState([]);

  // reviews (dummy for now)
  const [reviews, setReviews] = useState([
    { id: 1, user: "Karthik", rating: 5, comment: "Super quality 👌, very comfortable!" },
    { id: 2, user: "Meena", rating: 4, comment: "Worth the price, fast delivery 🚚" },
    { id: 3, user: "Rahul", rating: 3, comment: "Average product, expected better." }
  ]);

  // Fetch main product
  useEffect(() => {
    axios.get(`http://localhost:5000/api/products/${id}`)
      .then((res) => {
        setProduct(res.data);
        setSelectedImg(0);
        setSelectedSize(null);
      })
      .catch((err) => {
        console.error("Error fetching product details:", err);
      });
  }, [id]);

  // Fetch related products
  useEffect(() => {
    axios.get(`http://localhost:5000/api/products/${id}/related`)
      .then((res) => setRelated(res.data))
      .catch((err) => console.error("Related fetch error:", err));
  }, [id]);

  const handleCheckPincode = () => {
    const valid = /^[1-9][0-9]{5}$/.test(pincode);
    if (!valid) {
      setPinMsg('❌ Invalid pincode. Please enter a valid 6-digit pincode.');
      return;
    }
    const last = Number(pincode[pincode.length - 1]);
    if (last % 2 === 0) {
      setPinMsg('✅ Delivery available. Estimated delivery: 3–5 days.');
    } else {
      setPinMsg('✅ Delivery available. Estimated delivery: 5–7 days.');
    }
  };

  const handleAddToCart = () => {
    if (product?.sizes?.length && !selectedSize) {
      alert("Please select a size");
      return;
    }
    alert(`Added to Cart ${selectedSize ? `(Size: ${selectedSize})` : ''}!`);
  };

  const handleBuyNow = () => {
    if (product?.sizes?.length && !selectedSize) {
      alert("Please select a size");
      return;
    }
    navigate("/checkout");
  };

  if (!product) return <p>Loading...</p>;

  const gallery = (product.images && product.images.length > 0)
    ? product.images
    : (product.image ? [product.image] : []);

  const mainImg = gallery[selectedImg] || product.image;

  return (
    <>
      <div className="product-detail-container">
        {/* LEFT: Gallery */}
        <div className="product-gallery">
          <div className="main-image">
            <img src={mainImg} alt={product.name} />
          </div>
          {gallery.length > 1 && (
            <div className="thumbs">
              {gallery.map((src, idx) => (
                <button
                  key={idx}
                  className={`thumb ${idx === selectedImg ? 'active' : ''}`}
                  onClick={() => setSelectedImg(idx)}
                >
                  <img src={src} alt={`${product.name} ${idx + 1}`} />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* RIGHT: Info */}
        <div className="product-info-section">
          <h2>{product.name}</h2>
          <p className="price">₹{product.price}</p>

          {/* Sizes */}
          {product.sizes?.length > 0 ? (
            <div className="sizes-wrap">
              <p className="label">Select Size:</p>
              <div className="sizes">
                {product.sizes.map((s) => (
                  <button
                    key={s}
                    className={`size-chip ${selectedSize === s ? 'selected' : ''}`}
                    onClick={() => setSelectedSize(s)}
                  >
                    {s}
                  </button>
                ))}
              </div>
              <p className="size-info">
                Available: {product.sizes.join(", ")}
              </p>
            </div>
          ) : (
            <p className="size">Size: Free Size</p>
          )}

          {/* Description */}
          <p className="description">{product.description || "No description available."}</p>

          {/* Pincode checker */}
          <div className="pincode-checker">
            <input
              type="text"
              placeholder="Enter pincode"
              value={pincode}
              onChange={(e) => setPincode(e.target.value)}
              maxLength={6}
            />
            <button onClick={handleCheckPincode}>Check</button>
          </div>
          {pinMsg && <p className="pin-msg">{pinMsg}</p>}

          {/* Customer Ratings & Reviews */}
          <div className="reviews-section">
            <h3>Customer Ratings & Reviews</h3>
            {reviews.length > 0 ? (
              <ul className="review-list">
                {reviews.map((rev) => (
                  <li key={rev.id} className="review-item">
                    <p className="review-user"><strong>{rev.user}</strong></p>
                    <p className="review-rating">⭐ {rev.rating}/5</p>
                    <p className="review-comment">{rev.comment}</p>
                  </li>
                ))}
              </ul>
            ) : (
              <p>No reviews yet. Be the first to review!</p>
            )}
          </div>

          {/* Actions */}
          <div className="product-buttons">
            <button onClick={handleAddToCart} className="add-to-cart-btn">Add to Cart</button>
            <button onClick={handleBuyNow} className="buy-now-btn">Buy Now</button>
          </div>
        </div>
      </div>

      {/* Related products */}
      {related.length > 0 && (
        <div className="related-wrap">
          <h3>Related Products</h3>
          <div className="related-grid">
            {related.map((item) => (
              <Link
                to={`/products/${item._id}`}
                key={item._id}
                className="rel-card"
              >
                <div className="rel-img">
                  <img
                    src={(item.images && item.images[0]) || item.image}
                    alt={item.name}
                  />
                </div>
                <div className="rel-info">
                  <p className="rel-name">{item.name}</p>
                  <p className="rel-price">₹{item.price}</p>
                </div>
              </Link>
            ))}
          </div>
        </div>
      )}

      {/* Footer */}
      <Footer />
    </>
  );
}

export default ProductDetail;
